1	import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
2	import { renderHook, act } from "@testing-library/react";
3	import { SessionProvider, useSession } from "@/features/session/context";
4	import type { ReactNode } from "react";
5	
6	const STORAGE_KEY = "bayes-session";
7	
8	function wrapper({ children }: { children: ReactNode }) {
9	  return <SessionProvider>{children}</SessionProvider>;
10	}
11	
12	describe("Session context", () => {
13	  beforeEach(() => {
14	    localStorage.clear();
15	    vi.restoreAllMocks();
16	  });
17	
18	  describe("loadSession", () => {
19	    it("returns defaults when localStorage is empty", () => {
20	      const { result } = renderHook(() => useSession(), { wrapper });
21	      expect(result.current.session).toEqual({ accountId: "", agentId: "" });
22	    });
23	
24	    it("loads valid stored session", () => {
25	      localStorage.setItem(
26	        STORAGE_KEY,
27	        JSON.stringify({ accountId: "acc-1", agentId: "agent-1" }),
28	      );
29	      const { result } = renderHook(() => useSession(), { wrapper });
30	      expect(result.current.session).toEqual({ accountId: "acc-1", agentId: "agent-1" });
31	    });
32	
33	    it("returns defaults for invalid JSON (corrupt storage)", () => {
34	      localStorage.setItem(STORAGE_KEY, "not-json{{{");
35	      const { result } = renderHook(() => useSession(), { wrapper });
36	      expect(result.current.session).toEqual({ accountId: "", agentId: "" });
37	    });
38	
39	    it("returns defaults for valid JSON with missing fields", () => {
40	      localStorage.setItem(STORAGE_KEY, JSON.stringify({}));
41	      const { result } = renderHook(() => useSession(), { wrapper });
42	      expect(result.current.session).toEqual({ accountId: "", agentId: "" });
43	    });
44	
45	    it("returns partial data for valid JSON with only some fields", () => {
46	      localStorage.setItem(STORAGE_KEY, JSON.stringify({ accountId: "acc-2" }));
47	      const { result } = renderHook(() => useSession(), { wrapper });
48	      expect(result.current.session).toEqual({ accountId: "acc-2", agentId: "" });
49	    });
50	  });
51	
52	  describe("saveSession via SessionProvider", () => {
53	    it("setAccountId persists to localStorage", () => {
54	      const { result } = renderHook(() => useSession(), { wrapper });
55	      act(() => result.current.setAccountId("acc-new"));
56	      const stored = JSON.parse(localStorage.getItem(STORAGE_KEY)!);
57	      expect(stored.accountId).toBe("acc-new");
58	    });
59	
60	    it("setAgentId persists to localStorage", () => {
61	      const { result } = renderHook(() => useSession(), { wrapper });
62	      act(() => result.current.setAgentId("agent-new"));
63	      const stored = JSON.parse(localStorage.getItem(STORAGE_KEY)!);
64	      expect(stored.agentId).toBe("agent-new");
65	    });
66	
67	    it("writes correct JSON structure to storage", () => {
68	      const { result } = renderHook(() => useSession(), { wrapper });
69	      act(() => result.current.setAccountId("acc-x"));
70	      act(() => result.current.setAgentId("agent-y"));
71	      const stored = JSON.parse(localStorage.getItem(STORAGE_KEY)!);
72	      expect(stored).toEqual({ accountId: "acc-x", agentId: "agent-y" });
73	    });
74	  });
75	
76	  describe("isConfigured", () => {
77	    it("is false when both accountId and agentId are empty", () => {
78	      const { result } = renderHook(() => useSession(), { wrapper });
79	      expect(result.current.isConfigured).toBe(false);
80	    });
81	
82	    it("is true when accountId is set and agentId is empty", () => {
83	      localStorage.setItem(
84	        STORAGE_KEY,
85	        JSON.stringify({ accountId: "acc-1", agentId: "" }),
86	      );
87	      const { result } = renderHook(() => useSession(), { wrapper });
88	      expect(result.current.isConfigured).toBe(true);
89	    });
90	
91	    it("is false when accountId is empty and agentId is set", () => {
92	      localStorage.setItem(
93	        STORAGE_KEY,
94	        JSON.stringify({ accountId: "", agentId: "agent-1" }),
95	      );
96	      const { result } = renderHook(() => useSession(), { wrapper });
97	      expect(result.current.isConfigured).toBe(false);
98	    });
99	
100	    it("is true when both accountId and agentId are set", () => {
101	      localStorage.setItem(
102	        STORAGE_KEY,
103	        JSON.stringify({ accountId: "acc-1", agentId: "agent-1" }),
104	      );
105	      const { result } = renderHook(() => useSession(), { wrapper });
106	      expect(result.current.isConfigured).toBe(true);
107	    });
108	  });
109	
110	  describe("useSession outside provider", () => {
111	    const originalError = console.error;
112	    beforeEach(() => { console.error = vi.fn(); });
113	    afterEach(() => { console.error = originalError; });
114	
115	    it("throws when used outside SessionProvider", () => {
116	      expect(() => renderHook(() => useSession())).toThrow(
117	        "useSession must be used within SessionProvider",
118	      );
119	    });
120	  });
121	});
